using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 breaking change: Migrate() can no longer be called inside a
    // user-initiated transaction (throws InvalidOperationException).
    // Migrate() now manages its own transactions internally.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

